// 📁 src/auto-iteration.ts
import { getDashboardServices } from './dashboard/integration/dashboard-integration'

export class AutoIterationEngine {
  private dashboardServices = getDashboardServices()

  async startIteration(requirement: string) {
    // 1. 创建迭代记录
    const iteration = await this.dashboardServices.iteration.create({
      iterationNumber: this.count,
      status: 'running',
      requirement: requirement,
      startedAt: new Date()
    })

    // 2. 推送迭代开始事件
    this.dashboardServices.realtime.broadcastIterationStatusChange({
      iterationId: iteration.id,
      status: 'running',
      message: '开始新的迭代'
    })
  }

  async executeAgent(agentName: string, task: string) {
    // 推送 Agent 开始执行事件
    this.dashboardServices.realtime.broadcastAgentStatusChange({
      agentName,
      status: 'running',
      task
    })

    // 执行 Agent...
    const result = await this.agents[agentName].execute(task)

    // 推送 Agent 完成事件
    this.dashboardServices.realtime.broadcastAgentStatusChange({
      agentName,
      status: 'completed',
      result: result.substring(0, 500) // 前500字符
    })
  }

  async completeIteration(success: boolean) {
    // 更新迭代记录
    await this.dashboardServices.iteration.update(iterationId, {
      status: success ? 'completed' : 'failed',
      completedAt: new Date(),
      durationSeconds: Date.now() - startTime / 1000
    })

    // 推送完成事件
    this.dashboardServices.realtime.broadcastIterationStatusChange({
      iterationId,
      status: success ? 'completed' : 'failed'
    })
  }
}
```

