// 📁 src/dashboard/integration/dashboard-integration.ts (新文件)
import { IterationService } from '../services/iteration.service'
import { RealtimeService } from '../services/realtime.service'
import { DatabaseService } from '../services/database.service'
import { Logger } from 'pino'

let services: {
  iteration: IterationService
  realtime: RealtimeService
  database: DatabaseService
} | null = null

export function initDashboardServices(logger: Logger) {
  const db = new DatabaseService(logger)
  const realtime = new RealtimeService(logger)
  const iteration = new IterationService(db, logger)

  services = { iteration, realtime, database: db }
  return services
}

export function getDashboardServices() {
  if (!services) {
    throw new Error('Dashboard services not initialized. Call initDashboardServices first.')
  }
  return services
}
```

