// 📁 dashboard/src/utils/websocket-manager.ts
// 确保正确处理 WebSocket 事件
onMessage(event: MessageEvent) {
  try {
    const data = JSON.parse(event.data)

    // 根据事件类型分发
    switch (data.event) {
      case 'iteration.status_changed':
        this.emit('iteration.status_changed', data.data)
        break
      case 'agent.status_changed':
        this.emit('agent.status_changed', data.data)
        break
      case 'iteration.progress':
        this.emit('iteration.progress', data.data)
        break
      case 'system.metrics':
        this.emit('system.metrics', data.data)
        break
      case 'log.entry':
        this.emit('log.entry', data.data)
        break
      case 'ping':
        // 响应心跳
        this.send('pong')
        break
    }
  } catch (error) {
    console.error('Failed to parse WebSocket message:', error)
  }
}
```

