// 1. 实现 subscribe 方法
subscribe(client: WebSocket, channel: string) {
  if (!this.subscriptions.has(channel)) {
    this.subscriptions.set(channel, new Set());
  }
  this.subscriptions.get(channel)!.add(client);

  client.on('close', () => {
    this.unsubscribe(client, channel);
  });
}

// 2. 实现 broadcast 方法
broadcast(event: string, data: any) {
  const message = JSON.stringify({ event, data, timestamp: Date.now() });

  for (const [channel, clients] of this.subscriptions) {
    if (event.startsWith(channel)) {
      for (const client of clients) {
        if (client.readyState === WebSocket.OPEN) {
          client.send(message);
        }
      }
    }
  }
}

// 3. 添加频道管理
private subscriptions = new Map<string, Set<WebSocket>>();

unsubscribe(client: WebSocket, channel: string) {
  const clients = this.subscriptions.get(channel);
  if (clients) {
    clients.delete(client);
    if (clients.size === 0) {
      this.subscriptions.delete(channel);
    }
  }
}
```

