class MigrationService {
  async runPendingMigrations() {
    const currentVersion = await this.getCurrentVersion();
    const pending = this.migrations.filter(m => m.version > currentVersion);

    for (const migration of pending) {
      await this.runMigration(migration);
      await this.updateVersion(migration.version);
    }
  }

  async rollback(targetVersion: number) {
    const current = await this.getCurrentVersion();
    const toRollback = this.migrations
      .filter(m => m.version > targetVersion && m.version <= current)
      .sort((a, b) => b.version - a.version);

    for (const migration of toRollback) {
      if (migration.down) {
        await migration.down();
      }
    }

    await this.updateVersion(targetVersion);
  }
}
```

